#include <stdio.h>
#include <stdlib.h>
#include <string.h>
char *make_spaces(int n){ char *s=malloc(n+1); memset(s,' ',n); s[n]='\0'; return s; }
char **justify(char **words,int n,int maxWidth,int *ret){ char **res=malloc(sizeof(char*)*n); int rs=0,i=0; while(i<n){ int j=i,total=0; while(j<n && total+(int)strlen(words[j])+(j-i)<=maxWidth){ total += strlen(words[j]); j++; } int gaps=j-i-1; char *line=malloc(maxWidth+1); int pos=0; if(j==n||gaps==0){ for(int k=i;k<j;k++){ int len=strlen(words[k]); memcpy(line+pos,words[k],len); pos+=len; if(k+1<j) line[pos++]=' '; } while(pos<maxWidth) line[pos++]=' '; } else { int spaces=maxWidth-total, base=spaces/gaps, extra=spaces%gaps; for(int k=i;k<j-1;k++){ int len=strlen(words[k]); memcpy(line+pos,words[k],len); pos+=len; int cnt=base+((k-i<extra)?1:0); memset(line+pos,' ',cnt); pos+=cnt; } int len=strlen(words[j-1]); memcpy(line+pos,words[j-1],len); pos+=len; } line[maxWidth]='\0'; res[rs++]=line; i=j; } *ret=rs; return res; }
int main(){ int t; if(scanf("%d\n", &t)!=1) return 0; char buf[256]; for(int tc=0;tc<t;tc++){ int n; fgets(buf,sizeof(buf),stdin); n=atoi(buf); char **words=malloc(sizeof(char*)*n); for(int i=0;i<n;i++){ fgets(buf,sizeof(buf),stdin); buf[strcspn(buf,"\r\n")]=0; words[i]=strdup(buf);} fgets(buf,sizeof(buf),stdin); int width=atoi(buf), cnt=0; char **ans=justify(words,n,width,&cnt); printf("%d\n",cnt); for(int i=0;i<cnt;i++) printf("|%s|\n",ans[i]); if(tc+1<t) printf("=\n"); for(int i=0;i<n;i++) free(words[i]); free(words); for(int i=0;i<cnt;i++) free(ans[i]); free(ans);} return 0; }
